 3→import { Restaurant } from '../types'
 4→import { restaurantsCompleteData as restaurantsMock } from '../stub/restaurants'
 5→
 6→interface BaseApi {
 7→  getRestaurants: () => Promise<Restaurant[]>
 8→  getRestaurantById: (id: string) => Promise<Restaurant>
 9→  getRestaurantsByCategory: (category: string) => Promise<Restaurant[]>
10→}
11→
12→export const BASE_URL = 'https://mealdrop.netlify.app/.netlify/functions/restaurants'
13→
14→const isMockedEnvironment = !!import.meta.env.STORYBOOK || import.meta.env.NODE_ENV === 'test'
15→
16→const apiCache = new Map()
17→
18→const apiGet = async <T>(url: string): Promise<AxiosResponse<T>> => {
19→  // do not cache when testing to avoid flakyness
20→  if (!isMockedEnvironment && apiCache.has(url)) {
21→    return apiCache.get(url)
22→  }
23→
24→  const response = await axios.get<T>(url)
25→
26→  if (!isMockedEnvironment) {
27→    apiCache.set(url, response)
28→  }
29→
30→  return response
31→}
