import type { Preview } from '@storybook/react-vite'
import { initialize, mswLoader } from 'msw-storybook-addon'
import { Provider as StoreProvider } from 'react-redux'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { ThemeProvider } from 'styled-components'
import { configureStore } from '@reduxjs/toolkit'

import { rootReducer } from '../src/app-state/store'
import { lightTheme } from '../src/styles/theme'
import { GlobalStyle } from '../src/styles/GlobalStyle'
import { mswHandlers } from './msw-handlers'

initialize({
  onUnhandledRequest: 'bypass',
})

const preview: Preview = {
  decorators: [
    (Story, context) => {
      const store = configureStore({ reducer: rootReducer })
      const routerParams = context.parameters.reactRouter
      const initialEntries = routerParams?.initialEntries || ['/']
      const routePath = routerParams?.routePath

      return (
        <MemoryRouter initialEntries={initialEntries}>
          <StoreProvider store={store}>
            <ThemeProvider theme={lightTheme}>
              <GlobalStyle />
              {routePath ? (
                <Routes>
                  <Route path={routePath} element={<Story />} />
                </Routes>
              ) : (
                <Story />
              )}
            </ThemeProvider>
          </StoreProvider>
        </MemoryRouter>
      )
    },
  ],
  loaders: [mswLoader],
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
    a11y: {
      test: 'todo',
    },
    msw: {
      handlers: mswHandlers,
    },
  },
}

export default preview

import { http, HttpResponse } from 'msw'

import { restaurantsCompleteData } from '../src/stub/restaurants'

const BASE_URL = 'https://mealdrop.netlify.app/.netlify/functions/restaurants'

export const mswHandlers = [
  http.get(BASE_URL, ({ request }) => {
    const url = new URL(request.url)
    const id = url.searchParams.get('id')
    const category = url.searchParams.get('category')

    if (id) {
      const restaurant = restaurantsCompleteData.find((r) => r.id === id)
      if (restaurant) {
        return HttpResponse.json(restaurant)
      }
      return new HttpResponse(null, { status: 404 })
    }

    if (category) {
      const filtered = restaurantsCompleteData.filter((r) =>
        r.categories?.includes(category)
      )
      return HttpResponse.json(filtered)
    }

    return HttpResponse.json(restaurantsCompleteData)
  }),
]

